@* Displays a single task with priority badge and move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-details">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (CanMoveLeft)
        {
            <button class="btn-move btn-move-left" @onclick="OnMoveLeftClick">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn-move btn-move-right" @onclick="OnMoveRightClick">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task OnMoveLeftClick() => await OnMoveLeft.InvokeAsync(Task);
    private async System.Threading.Tasks.Task OnMoveRightClick() => await OnMoveRight.InvokeAsync(Task);
}

@* Inline form to create a new task within a column *@

<div class="add-task-form">
    <div class="form-group">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-group">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-group">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-group">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@saving">
            @(saving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@saving">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel() => await OnCancel.InvokeAsync();
}

@* A single Kanban column: header with count, task cards, and add-task toggle *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showAddForm)
        {
            <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
        }
        else
        {
            <button class="btn-add-task" @onclick="() => showAddForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool CanMoveLeft { get; set; }

    [Parameter]
    public bool CanMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showAddForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) newTask)
    {
        await OnTaskCreated.InvokeAsync(newTask);
        showAddForm = false;
    }

    private void HandleCancel() => showAddForm = false;
}

@* Search bar for client-side filtering of tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}

