@* Search bar for client-side filtering of tasks by title *@

<div class="search-bar">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchTerm { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}

arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h2>Kanban Board</h2>

@if (loading)
{
    <p class="board-loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="board-columns">
        @for (var i = 0; i < columns.Length; i++)
        {
            var col = columns[i];
            var colIndex = i;

            <BoardColumn ColumnName="@col"
                         Tasks="GetFilteredTasks(col)"
                         CanMoveLeft="colIndex > 0"
                         CanMoveRight="colIndex < columns.Length - 1"
                         OnMoveLeft="task => MoveTask(task, colIndex - 1)"
                         OnMoveRight="task => MoveTask(task, colIndex + 1)"
                         OnTaskCreated="data => CreateTask(data, col)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync() => await LoadTasks();

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task MoveTask(TaskItem task, int targetColumnIndex)
    {
        var newStatus = columns[targetColumnIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

.board-loading {
    text-align: center;
    padding: 2rem;
    color: #666;
}

.board-error {
    text-align: center;
    padding: 1rem;
    background: #fef2f2;
    border: 1px solid #fca5a5;
    border-radius: 0.5rem;
    color: #dc2626;
    margin-bottom: 1rem;
}

.board-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: 1px solid #dc2626;
    background: white;
    color: #dc2626;
    border-radius: 0.25rem;
    cursor: pointer;
}

/* Summary Bar */
.summary-bar {
    display: flex;
    gap: 1rem;
    margin-bottom: 1rem;
    padding: 0.75rem 1rem;
    background: #f8fafc;
    border: 1px solid #e2e8f0;
    border-radius: 0.5rem;
    flex-wrap: wrap;
}

.summary-stat {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 5rem;
}

.stat-value {
    font-size: 1.5rem;
    font-weight: 700;
    color: #1e293b;
}

.stat-label {
    font-size: 0.75rem;
    color: #64748b;
    text-transform: uppercase;
}

.stat-overdue .stat-value {
    color: #dc2626;
}

/* Search Bar */
.search-bar {
    margin-bottom: 1rem;
}

.search-bar input {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    font-size: 0.875rem;
    box-sizing: border-box;
}

/* Board Columns */
.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f1f5f9;
    border-radius: 0.5rem;
    padding: 0.75rem;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    color: #334155;
}

.column-count {
    background: #cbd5e1;
    color: #334155;
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.125rem 0.5rem;
    border-radius: 999px;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 2rem;
}

.column-footer {
    margin-top: 0.75rem;
}

/* Task Card */
.task-card {
    background: white;
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.875rem;
    color: #1e293b;
}

.priority-badge {
    font-size: 0.7rem;
    font-weight: 600;
    padding: 0.125rem 0.5rem;
    border-radius: 999px;
    text-transform: uppercase;
    white-space: nowrap;
}

.priority-high {
    background: #fee2e2;
    color: #dc2626;
}

.priority-medium {
    background: #fef9c3;
    color: #a16207;
}

.priority-low {
    background: #dcfce7;
    color: #16a34a;
}

.task-details {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: #64748b;
    margin-bottom: 0.5rem;
}

.task-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    flex: 1;
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    border: 1px solid #cbd5e1;
    background: #f8fafc;
    border-radius: 0.25rem;
    cursor: pointer;
    color: #475569;
}

.btn-move:hover {
    background: #e2e8f0;
}

/* Add Task */
.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    background: transparent;
    border: 2px dashed #cbd5e1;
    border-radius: 0.375rem;
    color: #64748b;
    cursor: pointer;
    font-size: 0.875rem;
}

.btn-add-task:hover {
    border-color: #94a3b8;
    color: #475569;
}

.add-task-form {
    background: white;
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.form-group {
    margin-bottom: 0.5rem;
}

.form-group label {
    display: block;
    font-size: 0.75rem;
    font-weight: 600;
    color: #475569;
    margin-bottom: 0.125rem;
}

.form-group input,
.form-group select {
    width: 100%;
    padding: 0.375rem 0.5rem;
    border: 1px solid #e2e8f0;
    border-radius: 0.25rem;
    font-size: 0.8rem;
    box-sizing: border-box;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

.btn-save {
    flex: 1;
    padding: 0.375rem;
    background: #2563eb;
    color: white;
    border: none;
    border-radius: 0.25rem;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-save:hover {
    background: #1d4ed8;
}

.btn-save:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.btn-cancel {
    flex: 1;
    padding: 0.375rem;
    background: white;
    border: 1px solid #cbd5e1;
    border-radius: 0.25rem;
    cursor: pointer;
    font-size: 0.8rem;
    color: #475569;
}

.btn-cancel:hover {
    background: #f1f5f9;
}

.btn-cancel:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

