    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    color: #334155;
}

.column-count {
    background: #cbd5e1;
    color: #334155;
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.125rem 0.5rem;
    border-radius: 999px;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 2rem;
}

.column-footer {
    margin-top: 0.75rem;
}

/* Task Card */
.task-card {
    background: white;
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.task-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.875rem;
    color: #1e293b;
}

.priority-badge {
    font-size: 0.7rem;
    font-weight: 600;
    padding: 0.125rem 0.5rem;
    border-radius: 999px;
    text-transform: uppercase;
    white-space: nowrap;
}

.priority-high {
    background: #fee2e2;
    color: #dc2626;
}

.priority-medium {
    background: #fef9c3;
    color: #a16207;
}

.priority-low {
    background: #dcfce7;
    color: #16a34a;
}

.task-details {
    display: flex;
    justify-content: space-between;
    font-size: 0.75rem;
    color: #64748b;
    margin-bottom: 0.5rem;
}

.task-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    flex: 1;
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    border: 1px solid #cbd5e1;
    background: #f8fafc;
    border-radius: 0.25rem;
    cursor: pointer;
    color: #475569;
}

.btn-move:hover {
    background: #e2e8f0;
}

