.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    background: transparent;
    border: 2px dashed #cbd5e1;
    border-radius: 0.375rem;
    color: #64748b;
    cursor: pointer;
    font-size: 0.875rem;
}

.btn-add-task:hover {
    border-color: #94a3b8;
    color: #475569;
}

.add-task-form {
    background: white;
    border: 1px solid #e2e8f0;
    border-radius: 0.375rem;
    padding: 0.75rem;
}

.form-group {
    margin-bottom: 0.5rem;
}

